# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, Response
import jwt
import requests
import json

app = Flask(__name__)

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def decode_token(token):
    try:
        payload = jwt.decode(token, options={"verify_signature": False})
        return payload
    except Exception as e:
        return None

def forward_to_backend(path, claims):
    backend_url = f"http://localhost:5001{path}"
    
    headers = {
        'Content-Type': 'application/json',
        'X-User-Id': str(claims.get('user_id', '')),
        'X-User-Email': str(claims.get('email', '')),
        'X-User-Role': str(claims.get('role', '')),
        'X-User-Claims': json.dumps(claims)
    }
    
    if request.method == 'GET':
        response = requests.get(backend_url, headers=headers, params=request.args)
    elif request.method == 'POST':
        response = requests.post(backend_url, headers=headers, json=request.get_json(silent=True))
    elif request.method == 'PUT':
        response = requests.put(backend_url, headers=headers, json=request.get_json(silent=True))
    elif request.method == 'DELETE':
        response = requests.delete(backend_url, headers=headers)
    elif request.method == 'PATCH':
        response = requests.patch(backend_url, headers=headers, json=request.get_json(silent=True))
    else:
        return jsonify({'error': 'Method not allowed'}), 405
    
    return Response(
        response.content,
        status=response.status_code,
        headers=dict(response.headers)
    )

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway(path):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = decode_token(token)
    
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    return forward_to_backend(f"/{path}", claims)

@app.route('/', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway_root():
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = decode_token(token)
    
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    return forward_to_backend("/", claims)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)